import{_ as a,o as n,c as s,ag as e}from"./chunks/framework.CxZWPeXl.js";const b=JSON.parse('{"title":"評量報告","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/evaluation.md","filePath":"zh-TW/evaluation.md"}'),r={name:"zh-TW/evaluation.md"};function d(l,t,i,o,h,p){return n(),s("div",null,[...t[0]||(t[0]=[e(`<h1 id="評量報告" tabindex="-1">評量報告 <a class="header-anchor" href="#評量報告" aria-label="Permalink to &quot;評量報告&quot;">​</a></h1><blockquote><p>從整體表現到每一句對話，獲得完整且具體的專業回饋</p></blockquote><h2 id="概覽" tabindex="-1">概覽 <a class="header-anchor" href="#概覽" aria-label="Permalink to &quot;概覽&quot;">​</a></h2><p>每次練習結束後，AI Coach 會自動產生詳細的評量報告。報告涵蓋三個層次的分析：</p><ol><li><strong>階段評量</strong> — 各銷售階段的達成與否及改善建議</li><li><strong>綜合評核</strong> — 整體表現的總結與學習方向</li><li><strong>逐句評價</strong> — 每則訊息的細緻分析</li></ol><p>這三種報告各自獨立產生，使用不同的 AI Agent，分析不同面向的表現。</p><hr><h2 id="報告產生流程" tabindex="-1">報告產生流程 <a class="header-anchor" href="#報告產生流程" aria-label="Permalink to &quot;報告產生流程&quot;">​</a></h2><h3 id="觸發時機" tabindex="-1">觸發時機 <a class="header-anchor" href="#觸發時機" aria-label="Permalink to &quot;觸發時機&quot;">​</a></h3><p>當您點擊「結束對話」（或客戶發起結束後您確認結束）時，系統會：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>檢查對話狀態 → 關閉對話 → 同時觸發三個背景任務</span></span>
<span class="line"><span>                              ├─ 階段評量產生</span></span>
<span class="line"><span>                              ├─ 綜合評核產生</span></span>
<span class="line"><span>                              └─ 對話摘要產生</span></span></code></pre></div><blockquote><p>注意：<strong>逐句評價</strong>不在結束時才產生，而是在對話過程中每輪訊息結束後即在背景產生（詳見下方說明）。</p></blockquote><h3 id="前端顯示狀態" tabindex="-1">前端顯示狀態 <a class="header-anchor" href="#前端顯示狀態" aria-label="Permalink to &quot;前端顯示狀態&quot;">​</a></h3><p>產生過程中會顯示狀態覆蓋層：</p><table tabindex="0"><thead><tr><th>狀態</th><th>顯示訊息</th></tr></thead><tbody><tr><td>檢查中</td><td>正在檢查對話狀態...</td></tr><tr><td>關閉對話</td><td>正在關閉對話，準備生成評核報告...</td></tr><tr><td>產生中</td><td>評核報告生成中... / 我們正在為您生成詳細的評核報告</td></tr></tbody></table><blockquote><p>報告產生通常需要 30 秒至 2 分鐘。如超過 5 分鐘仍未完成，可嘗試重新整理頁面。</p></blockquote><h3 id="產生狀態" tabindex="-1">產生狀態 <a class="header-anchor" href="#產生狀態" aria-label="Permalink to &quot;產生狀態&quot;">​</a></h3><p>報告中的各個區塊（階段評量、綜合評核等）各自獨立產生，可能有以下狀態：</p><table tabindex="0"><thead><tr><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>排隊中 (queued)</td><td>任務已建立，等待執行</td></tr><tr><td>處理中 (processing)</td><td>正在產生內容</td></tr><tr><td>完成 (available)</td><td>內容已產生完成，可以檢視</td></tr><tr><td>未請求 (not_requested)</td><td>尚未觸發產生</td></tr><tr><td>失敗 (failed)</td><td>產生過程發生錯誤</td></tr><tr><td>跳過 (skipped)</td><td>因無對話內容或其他原因被跳過</td></tr></tbody></table><hr><h2 id="報告頁面" tabindex="-1">報告頁面 <a class="header-anchor" href="#報告頁面" aria-label="Permalink to &quot;報告頁面&quot;">​</a></h2><p>報告頁面頂部顯示標題「業務員對話練習綜合評核」，並提供兩個檢視模式切換：</p><table tabindex="0"><thead><tr><th>模式</th><th>說明</th></tr></thead><tbody><tr><td>綜合評核</td><td>查看整體階段評量與綜合分析（預設）</td></tr><tr><td>逐句評價</td><td>查看每則訊息的詳細評價</td></tr></tbody></table><h3 id="返回操作" tabindex="-1">返回操作 <a class="header-anchor" href="#返回操作" aria-label="Permalink to &quot;返回操作&quot;">​</a></h3><p>頁面左上方提供「返回列表」按鈕，可回到儀表板或練習歷史頁面。</p><hr><h2 id="一、階段評量" tabindex="-1">一、階段評量 <a class="header-anchor" href="#一、階段評量" aria-label="Permalink to &quot;一、階段評量&quot;">​</a></h2><h3 id="階段評量的分析目的" tabindex="-1">階段評量的分析目的 <a class="header-anchor" href="#階段評量的分析目的" aria-label="Permalink to &quot;階段評量的分析目的&quot;">​</a></h3><p>階段評量是在對話結束後，由 AI 一次性回顧完整對話內容，根據管理員定義的各階段標準，判定您最終達成了哪些銷售階段，並為每個已達成的階段撰寫獨立的評量分析。</p><h3 id="階段評量的資料輸入" tabindex="-1">階段評量的資料輸入 <a class="header-anchor" href="#階段評量的資料輸入" aria-label="Permalink to &quot;階段評量的資料輸入&quot;">​</a></h3><p>AI 在產生階段評量時，會取得以下資訊作為分析依據：</p><table tabindex="0"><thead><tr><th>輸入資料</th><th>說明</th></tr></thead><tbody><tr><td>完整對話紀錄</td><td>包含每一輪的：使用者訊息、客戶內心活動、客戶回應</td></tr><tr><td>階段定義</td><td>管理員設定的所有階段，包含階段名稱與客戶狀態描述</td></tr><tr><td>最大階段編號</td><td>目前定義的最高階段數（例如 5）</td></tr><tr><td>客戶角色資料</td><td>客戶的個人屬性（年齡、職業、收入、MBTI 等）</td></tr><tr><td>客戶詳細描述</td><td>系統產生的客戶角色完整描述文字</td></tr></tbody></table><h3 id="階段評量的產生邏輯" tabindex="-1">階段評量的產生邏輯 <a class="header-anchor" href="#階段評量的產生邏輯" aria-label="Permalink to &quot;階段評量的產生邏輯&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>對話結束</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>系統建立「階段評量」背景任務（狀態：排隊中）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>背景任務開始執行（狀態：處理中）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>AI Agent 接收完整對話紀錄與所有階段定義</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>AI 以單次分析判定每個階段的達成情況</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>輸出結構化的 JSON 格式（每個階段一筆評量）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>系統儲存評量結果，更新該次練習的「達成階段」欄位（狀態：完成）</span></span></code></pre></div><p><strong>重要特性</strong>：</p><ul><li>使用<strong>單一 AI Agent</strong> 一次分析所有階段，而非每個階段各跑一次</li><li>AI 可存取對話中的<strong>客戶內心活動</strong>（即客戶的心理分析），用以更精準地判斷階段推進</li><li>若對話沒有任何內容，系統會跳過評量產生（狀態標記為「跳過」）</li></ul><h3 id="階段評量的輸出結果" tabindex="-1">階段評量的輸出結果 <a class="header-anchor" href="#階段評量的輸出結果" aria-label="Permalink to &quot;階段評量的輸出結果&quot;">​</a></h3><p>AI 會為每個已達成的階段產生一筆評量紀錄，每筆包含：</p><table tabindex="0"><thead><tr><th>輸出欄位</th><th>說明</th></tr></thead><tbody><tr><td>階段編號</td><td>所評量的階段編號</td></tr><tr><td>評量內容</td><td>AI 對使用者在該階段表現的詳細分析文字</td></tr></tbody></table><p>此外，系統會根據評量結果更新：</p><ul><li><strong>達成階段</strong>：該次練習的最高達成階段編號（記錄於練習紀錄中）</li><li><strong>是否達成所有階段</strong>：若 AI 判定通過所有階段，會標記完成旗標</li></ul><h3 id="階段評量的評核要點" tabindex="-1">階段評量的評核要點 <a class="header-anchor" href="#階段評量的評核要點" aria-label="Permalink to &quot;階段評量的評核要點&quot;">​</a></h3><p>AI 在評量每個階段時，主要分析以下面向：</p><ol><li><strong>階段目標達成度</strong> — 對照該階段的定義描述，判斷使用者是否達成該階段的核心目標</li><li><strong>客戶狀態推進</strong> — 對照「客戶狀態描述」，判斷客戶的心理狀態是否從該階段的起始狀態推進到下一階段</li><li><strong>對話技巧運用</strong> — 使用者在該階段使用的溝通策略是否有效</li><li><strong>客戶互動品質</strong> — 客戶的參與度、信任度、開放程度是否有提升</li><li><strong>未晉升原因</strong>（若適用）— 具體分析為何未能推進至更高階段，提供改善方向</li></ol><h3 id="階段評量的頁面呈現" tabindex="-1">階段評量的頁面呈現 <a class="header-anchor" href="#階段評量的頁面呈現" aria-label="Permalink to &quot;階段評量的頁面呈現&quot;">​</a></h3><p>依據評量結果，會呈現以下其中一種情況：</p><p><strong>情況一：達成部分階段</strong></p><p>每個已達成的階段會以可展開/收合的卡片顯示：</p><ul><li>標題格式：「第 N 階段：{階段名稱}」</li><li>內容：AI 對您在該階段表現的詳細分析</li></ul><p>接著顯示「未晉升原因」區塊：</p><ul><li>內容：AI 分析您未能晉升至下一階段的具體原因與改善建議</li></ul><p><strong>情況二：達成所有階段</strong></p><ul><li>所有階段的評量卡片</li><li>額外顯示：「您已達成所有階段」與恭喜訊息</li></ul><p><strong>情況三：未達成任何階段</strong></p><ul><li>顯示：「未達成任何評核階段。」</li><li>表示 AI 判斷對話尚未達到第一個階段的標準（可能因對話輪數不足或內容未切入銷售主題）</li></ul><blockquote><p>標題旁有說明按鈕，點擊可查看管理員定義的各階段定義說明。</p></blockquote><hr><h2 id="二、綜合評核" tabindex="-1">二、綜合評核 <a class="header-anchor" href="#二、綜合評核" aria-label="Permalink to &quot;二、綜合評核&quot;">​</a></h2><h3 id="綜合評核的分析目的" tabindex="-1">綜合評核的分析目的 <a class="header-anchor" href="#綜合評核的分析目的" aria-label="Permalink to &quot;綜合評核的分析目的&quot;">​</a></h3><p>綜合評核是對整次練習的整體表現進行全面分析，提供總結性的評價與學習方向建議。與階段評量不同，綜合評核不聚焦於單一階段，而是從整體對話品質、銷售技巧、客戶經營等角度給出綜合回饋。</p><h3 id="綜合評核的資料輸入" tabindex="-1">綜合評核的資料輸入 <a class="header-anchor" href="#綜合評核的資料輸入" aria-label="Permalink to &quot;綜合評核的資料輸入&quot;">​</a></h3><p>AI 在產生綜合評核時，會取得以下資訊作為分析依據：</p><table tabindex="0"><thead><tr><th>輸入資料</th><th>說明</th></tr></thead><tbody><tr><td>完整對話紀錄</td><td>包含每一輪的：使用者訊息、客戶內心活動、客戶回應</td></tr><tr><td>客戶角色資料</td><td>客戶的個人屬性（年齡、職業、收入、MBTI 等）</td></tr><tr><td>客戶詳細描述</td><td>系統產生的客戶角色完整描述文字</td></tr><tr><td>練習時長</td><td>本次對話的總時長（秒）</td></tr></tbody></table><blockquote><p>注意：綜合評核<strong>不會</strong>直接取得階段評量的結果作為輸入。兩者是由不同的 AI Agent <strong>平行且獨立</strong>產生的。</p></blockquote><h3 id="綜合評核的產生邏輯" tabindex="-1">綜合評核的產生邏輯 <a class="header-anchor" href="#綜合評核的產生邏輯" aria-label="Permalink to &quot;綜合評核的產生邏輯&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>對話結束</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>系統建立「綜合評核」背景任務（狀態：排隊中）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>背景任務開始執行（狀態：處理中）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>AI Agent 接收完整對話紀錄與客戶資料</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>AI 從整體角度分析對話表現</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>輸出 Markdown 格式的評核文字</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>系統儲存評核結果（狀態：完成）</span></span></code></pre></div><p><strong>重要特性</strong>：</p><ul><li>與階段評量<strong>平行產生</strong>，互不依賴</li><li>若對話沒有任何內容，系統會跳過產生（狀態標記為「跳過」）</li><li>產生失敗不影響階段評量與逐句評價的產生</li></ul><h3 id="綜合評核的輸出結果" tabindex="-1">綜合評核的輸出結果 <a class="header-anchor" href="#綜合評核的輸出結果" aria-label="Permalink to &quot;綜合評核的輸出結果&quot;">​</a></h3><p>綜合評核產生一段 Markdown 格式的文字，通常在報告的「綜合評核」標籤頁中包含以下區塊：</p><table tabindex="0"><thead><tr><th>輸出區塊</th><th>說明</th></tr></thead><tbody><tr><td>Persona Card (角色卡片)</td><td>頁面最上方快速回顧客戶的基本資料設定</td></tr><tr><td>角色詳細訊息</td><td>客戶的完整背景故事與性格描述分析</td></tr><tr><td>階段評核說明</td><td>列出所有銷售階段 (1-5) 及其定義標準</td></tr><tr><td>整體表現總評</td><td>一段總結性描述，概述本次練習的整體表現</td></tr><tr><td>優點 (Strengths)</td><td>條列式列舉使用者在對話中表現良好的具體面向</td></tr><tr><td>待改進 (Areas for Improvement)</td><td>條列式指出對話中可以做得更好的部分</td></tr><tr><td>建議 (Suggestions)</td><td>針對待改善項目提供可操作的明確建議</td></tr></tbody></table><blockquote><p>實際內容的區塊結構與詳細程度由 AI Agent 的 Prompt 設定決定，管理員可透過 <a href="./admin-prompts.html">Prompt 管理</a> 調整。</p></blockquote><h3 id="綜合評核的評核要點" tabindex="-1">綜合評核的評核要點 <a class="header-anchor" href="#綜合評核的評核要點" aria-label="Permalink to &quot;綜合評核的評核要點&quot;">​</a></h3><p>AI 在產生綜合評核時，主要分析以下面向：</p><ol><li><strong>對話品質</strong> — 開場是否自然、對話節奏是否流暢、結束是否得體</li><li><strong>銷售技巧</strong> — 是否運用開放式問題、積極傾聽、需求引導等技巧</li><li><strong>客戶關係經營</strong> — 是否展現同理心、建立信任、維護良好互動</li><li><strong>專業知識展現</strong> — 是否展示對產品與市場的專業理解</li><li><strong>客戶理解程度</strong> — 是否充分了解客戶的需求、擔憂與期望</li><li><strong>整體策略</strong> — 對話的推進策略是否合理有效</li></ol><h3 id="綜合評核的頁面呈現" tabindex="-1">綜合評核的頁面呈現 <a class="header-anchor" href="#綜合評核的頁面呈現" aria-label="Permalink to &quot;綜合評核的頁面呈現&quot;">​</a></h3><ul><li>標題：「綜合評核」</li><li>內容：以 Markdown 格式呈現，支援標題、列表、粗體等排版</li><li>若未通過任何階段，會顯示「未通過任何階段。」</li></ul><hr><h2 id="三、逐句評價" tabindex="-1">三、逐句評價 <a class="header-anchor" href="#三、逐句評價" aria-label="Permalink to &quot;三、逐句評價&quot;">​</a></h2><h3 id="逐句評價的分析目的" tabindex="-1">逐句評價的分析目的 <a class="header-anchor" href="#逐句評價的分析目的" aria-label="Permalink to &quot;逐句評價的分析目的&quot;">​</a></h3><p>逐句評價是針對對話中的<strong>每一輪訊息</strong>進行個別分析，讓您可以精確了解每次發言的優劣之處。這是最細緻的回饋層級，適合深入檢視特定對話環節。</p><h3 id="逐句評價的資料輸入" tabindex="-1">逐句評價的資料輸入 <a class="header-anchor" href="#逐句評價的資料輸入" aria-label="Permalink to &quot;逐句評價的資料輸入&quot;">​</a></h3><p>AI 在產生每一輪的逐句評價時，會取得以下資訊作為分析依據：</p><table tabindex="0"><thead><tr><th>輸入資料</th><th>說明</th></tr></thead><tbody><tr><td>截至該輪的完整對話紀錄</td><td>包含先前所有輪次的對話與已產生的評價</td></tr><tr><td>該輪的使用者訊息</td><td>使用者（業務員）在該輪發送的訊息</td></tr><tr><td>該輪的客戶內心活動</td><td>AI 客戶在該輪的心理分析</td></tr><tr><td>該輪的客戶回應</td><td>AI 客戶在該輪的實際回覆</td></tr><tr><td>階段定義</td><td>管理員設定的所有階段與最大階段編號</td></tr><tr><td>客戶角色資料</td><td>客戶的個人屬性與詳細描述</td></tr></tbody></table><h3 id="逐句評價的產生邏輯" tabindex="-1">逐句評價的產生邏輯 <a class="header-anchor" href="#逐句評價的產生邏輯" aria-label="Permalink to &quot;逐句評價的產生邏輯&quot;">​</a></h3><p>與階段評量和綜合評核不同，逐句評價是<strong>在對話過程中即時產生</strong>的，而非等到對話結束後：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者發送訊息</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>系統產生 AI 客戶的內心活動與回應（同步，使用者等待）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>將回應即時回傳給使用者</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>同時在背景建立「逐句評價」任務（狀態：排隊中）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>背景任務開始執行（狀態：處理中）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>AI Agent 分析該輪對話表現</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>儲存評價結果（狀態：完成）</span></span></code></pre></div><p><strong>重要特性</strong>：</p><ul><li><strong>不阻塞對話流程</strong>：使用者發送訊息後，會立即收到 AI 客戶的回應，逐句評價在背景非同步產生</li><li><strong>每輪獨立產生</strong>：每一輪對話（chat_order）對應一筆獨立的逐句評價</li><li><strong>累積上下文</strong>：後續輪次的評價可參考先前的對話紀錄與已產生的評價</li><li>在對話結束進入報告頁面時，大部分逐句評價通常已經產生完成</li></ul><h3 id="逐句評價的輸出結果" tabindex="-1">逐句評價的輸出結果 <a class="header-anchor" href="#逐句評價的輸出結果" aria-label="Permalink to &quot;逐句評價的輸出結果&quot;">​</a></h3><p>每一輪對話的逐句評價包含：</p><table tabindex="0"><thead><tr><th>輸出欄位</th><th>說明</th></tr></thead><tbody><tr><td>對話輪次 (chat_order)</td><td>該評價對應的第幾輪對話</td></tr><tr><td>評價內容</td><td>AI 對該輪使用者表現的詳細分析（Markdown 格式）</td></tr><tr><td>產生狀態</td><td>該輪評價的當前狀態（完成 / 處理中 / 失敗等）</td></tr></tbody></table><h3 id="逐句評價的評核要點" tabindex="-1">逐句評價的評核要點 <a class="header-anchor" href="#逐句評價的評核要點" aria-label="Permalink to &quot;逐句評價的評核要點&quot;">​</a></h3><p>AI 在產生逐句評價時，主要分析以下面向：</p><ol><li><strong>表達方式</strong> — 用字遣詞是否得當、語氣是否合適、是否清晰易懂</li><li><strong>銷售技巧</strong> — 該輪是否有效運用提問、傾聽、引導等銷售技巧</li><li><strong>客戶關係維護</strong> — 該輪回應是否有助於建立或維持與客戶的信任關係</li><li><strong>階段推進效果</strong> — 該輪對話對推進銷售階段是否有正面貢獻</li><li><strong>客戶心理回應</strong> — 分析客戶在該輪的內心反應，幫助理解對話的實際效果</li><li><strong>具體改善建議</strong> — 針對該輪的具體情境提出可操作的改進方向</li></ol><h3 id="逐句評價的頁面呈現" tabindex="-1">逐句評價的頁面呈現 <a class="header-anchor" href="#逐句評價的頁面呈現" aria-label="Permalink to &quot;逐句評價的頁面呈現&quot;">​</a></h3><p>切換至「逐句評價」模式後，每一輪對話（您的訊息 + AI 客戶回覆）會顯示為一張卡片，包含：</p><table tabindex="0"><thead><tr><th>區塊</th><th>說明</th></tr></thead><tbody><tr><td>您的訊息</td><td>右側藍色氣泡，顯示您發送的訊息內容</td></tr><tr><td>AI 客戶回覆</td><td>左側灰色氣泡，顯示 AI 客戶的回覆</td></tr><tr><td>AI 內心思考</td><td>標題「AI內心思考」，顯示 AI 分析客戶在該輪對話中的心理活動與想法</td></tr><tr><td>逐句評價</td><td>標題「逐句評價」，Markdown 格式的詳細分析</td></tr></tbody></table><p>每一輪對話下方都有獨立的評分區塊，評分方式與綜合評核的回饋評分相同（正面 / 中立 / 負面）。</p><hr><h2 id="三種報告的比較" tabindex="-1">三種報告的比較 <a class="header-anchor" href="#三種報告的比較" aria-label="Permalink to &quot;三種報告的比較&quot;">​</a></h2><table tabindex="0"><thead><tr><th>面向</th><th>階段評量</th><th>綜合評核</th><th>逐句評價</th></tr></thead><tbody><tr><td><strong>分析範圍</strong></td><td>各銷售階段的達成情況</td><td>整次練習的整體表現</td><td>每一輪訊息的個別表現</td></tr><tr><td><strong>產生時機</strong></td><td>對話結束後</td><td>對話結束後</td><td>對話過程中（每輪即時背景產生）</td></tr><tr><td><strong>AI Agent</strong></td><td>stage_review_agent</td><td>final_review_agent</td><td>overall_assessment_agent</td></tr><tr><td><strong>主要輸入</strong></td><td>完整對話 + 階段定義</td><td>完整對話 + 練習時長</td><td>截至該輪的對話 + 階段定義</td></tr><tr><td><strong>輸出格式</strong></td><td>每階段一筆結構化評量</td><td>一段 Markdown 綜合分析</td><td>每輪一筆 Markdown 評價</td></tr><tr><td><strong>互相依賴</strong></td><td>獨立產生</td><td>獨立產生</td><td>獨立產生</td></tr><tr><td><strong>適合用途</strong></td><td>了解階段達成與未晉升原因</td><td>獲得整體回饋與學習方向</td><td>逐一檢視每次發言的優劣</td></tr></tbody></table><hr><h2 id="回饋評分" tabindex="-1">回饋評分 <a class="header-anchor" href="#回饋評分" aria-label="Permalink to &quot;回饋評分&quot;">​</a></h2><h3 id="綜合評核的回饋" tabindex="-1">綜合評核的回饋 <a class="header-anchor" href="#綜合評核的回饋" aria-label="Permalink to &quot;綜合評核的回饋&quot;">​</a></h3><p>在綜合評核模式下方，提供回饋評分區塊：</p><ul><li>標題：「喜歡這次評核內容嗎？」</li><li>說明：「針對階段評核與綜合評核提供意見回饋，以協助提升服務品質與整體體驗。」</li></ul><table tabindex="0"><thead><tr><th>選項</th><th>操作</th><th>說明</th></tr></thead><tbody><tr><td>正面</td><td>點擊讚按鈕</td><td>覺得評核內容有幫助，可附加留言（選填）</td></tr><tr><td>中立</td><td>預設狀態（不需操作）</td><td>預設值，無特別意見。再次點擊已選的按鈕可回到中立</td></tr><tr><td>負面</td><td>點擊倒讚按鈕</td><td>覺得評核需要改善，需附加留言說明原因（必填）</td></tr></tbody></table><h3 id="逐句評價的回饋" tabindex="-1">逐句評價的回饋 <a class="header-anchor" href="#逐句評價的回饋" aria-label="Permalink to &quot;逐句評價的回饋&quot;">​</a></h3><p>每一輪對話的逐句評價下方都有獨立的評分區塊，評分方式相同（正面 / 中立 / 負面）。這讓您可以針對 AI 在特定訊息上的評價品質提供回饋，幫助系統持續優化。</p><hr><h2 id="評量報告的使用建議" tabindex="-1">評量報告的使用建議 <a class="header-anchor" href="#評量報告的使用建議" aria-label="Permalink to &quot;評量報告的使用建議&quot;">​</a></h2><h3 id="如何有效利用評量報告" tabindex="-1">如何有效利用評量報告 <a class="header-anchor" href="#如何有效利用評量報告" aria-label="Permalink to &quot;如何有效利用評量報告&quot;">​</a></h3><ol><li><strong>先看階段評量</strong> — 了解自己在哪些階段表現良好、哪些需要加強</li><li><strong>閱讀未晉升原因</strong> — 如果未達成所有階段，仔細閱讀原因分析</li><li><strong>查看綜合評核</strong> — 了解 AI 對整體表現的觀察與建議</li><li><strong>切換逐句評價</strong> — 針對表現不佳的階段，回顧具體的對話細節</li><li><strong>關注 AI 內心思考</strong> — 了解客戶在各階段的心理狀態，有助下次調整策略</li><li><strong>提供回饋評分</strong> — 您的評分有助於系統持續優化評量品質</li></ol><h3 id="持續改善循環" tabindex="-1">持續改善循環 <a class="header-anchor" href="#持續改善循環" aria-label="Permalink to &quot;持續改善循環&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查看評量 → 找出弱點 → 重新挑戰相同客戶 → 對比前後表現 → 逐步提升</span></span></code></pre></div><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>到 <a href="./history.html">練習歷史</a> 查看過去的練習並重新挑戰</li><li>使用 <a href="./knowledge-assistant.html">知識助手</a> 補充銷售知識</li><li>回到 <a href="./dashboard.html">儀表板</a> 追蹤整體進步</li></ul>`,119)])])}const g=a(r,[["render",d]]);export{b as __pageData,g as default};
